package utils

import org.owasp.html.HtmlPolicyBuilder
import org.owasp.html.PolicyFactory
import play.twirl.api.Html

object HtmlSanitizer {

  private val policy: PolicyFactory = new HtmlPolicyBuilder()
    .allowElements("p", "br", "div", "span", "blockquote", "pre", "code")
    .allowElements("b", "strong", "i", "em", "u", "s", "strike", "sub", "sup")
    .allowElements("h1", "h2", "h3", "h4", "h5", "h6")
    .allowElements("ul", "ol", "li")
    .allowElements("a")
    .allowAttributes("href").onElements("a")
    .allowAttributes("title").onElements("a")
    .allowAttributes("target").onElements("a")
    .requireRelNofollowOnLinks()
    .allowElements("img")
    .allowAttributes("src", "alt", "title", "width", "height").onElements("img")
    .allowUrlProtocols("https", "http")
    .allowElements("table", "thead", "tbody", "tr", "td", "th")
    .allowAttributes("class").globally()
    .toFactory()

  def sanitize(untrustedHtml: String): Html = {
    val sanitized = policy.sanitize(untrustedHtml)
    Html(sanitized)
  }
}